const COLORS = [
  'bg-red-900/40',
  'bg-orange-900/40',
  'bg-amber-900/40',
  'bg-yellow-900/40',
  'bg-lime-900/40',
  'bg-emerald-900/40',
  'bg-teal-900/40',
  'bg-cyan-900/40',
  'bg-sky-900/40',
  'bg-blue-900/40',
  'bg-indigo-900/40',
