export const Portfolio: React.FC = () => {
  const [activeColor, setActiveColor] = useState<string>('bg-zinc-950');
  const [activeItem, setActiveItem] = useState<string | null>(null);
  const [items, setItems] = useState<PortfolioItem[]>([]);

  useEffect(() => {
    const fetchPortfolio = async () => {
      // Fetch name, image, category and created_at from the portfolio table
      const { data, error } = await supabase
        .from('portfolio')
        .select('id, name, image, category, created_at')
        .order('created_at', { ascending: true });

      if (!error && data) {
        // Map DB fields to UI model, injecting cyclic colors for visual flair
        const mappedItems: PortfolioItem[] = data.map((item: any, index: number) => ({
          id: item.id,
          name: item.name,
          image: item.image,
          category: item.category || 'F&B Excellence', // Fallback if column is empty
          color: COLORS[index % COLORS.length]
        }));
        setItems(mappedItems);
      } else if (error) {
        console.error('Error fetching portfolio data:', error);
      }
    };
    fetchPortfolio();
  }, []);

  // Don't render the section if there are no items to show
  if (items.length === 0) {
    return null; 
  }

  return (
    <section 
      id="portfolio" 
      className={`py-24 px-4 transition-colors duration-700 ease-in-out ${activeColor} relative border-t border-zinc-800`}
    >
      <div className="max-w-7xl mx-auto">
        <div className="flex flex-col md:flex-row justify-between items-end mb-16 border-b border-white/10 pb-8">
          <div>
            <h2 className="text-white/60 font-mono text-sm uppercase tracking-widest mb-4">The Tasting Menu</h2>
            <h3 className="font-archivo text-5xl md:text-7xl text-white uppercase">SUCCESS STORIES</h3>
          </div>
          <div className="text-right hidden md:block">
            <p className="font-mono text-white/50 text-sm">Hover to explore <br/> our impact.</p>
          </div>
        </div>

        <div className="grid grid-cols-1 gap-0">
          {items.map((item, index) => (
