export const Team: React.FC = () => {
  const [teamMembers, setTeamMembers] = useState<Operator[]>(fallbackTeamMembers);

  useEffect(() => {
    const fetchTeam = async () => {
      try {
        const { data, error } = await supabase
          .from('team')
          .select('*')
          .order('id', { ascending: true });

        if (error) {
          console.error('Error fetching team data from Supabase:', error);
          return;
        }

        if (data && data.length > 0) {
          // Cache busting: Append a timestamp to force the browser to re-download 
          // updated images even if the filename hasn't changed.
          const cacheBuster = Date.now();
          const updatedMembers = data.map((member: any) => ({
            ...member,
            image: member.image.includes('?') 
              ? `${member.image}&v=${cacheBuster}` 
              : `${member.image}?v=${cacheBuster}`
          }));
          setTeamMembers(updatedMembers);
        }
      } catch (err) {
        console.error('Unexpected error in fetchTeam:', err);
      }
    };
    fetchTeam();
  }, []);

  return (
    <section id="team" className="py-32 px-4 bg-zinc-950 border-t border-zinc-800 relative">
