            </div>
        </div>

        {/* Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 justify-center">
            {teamMembers.map((member) => (
                <div key={member.id} className="group relative bg-zinc-900 border border-zinc-800 hover:border-orange-600 transition-colors duration-300 flex flex-col">

